AFTER UPDATE OF player_name ON player 
FOR EACH ROW 
EXECUTE PROCEDURE log_player_name_changes()

-- For a simple try without waiting (returns immediately)
SELECT pg_try_advisory_lock(lkhndl);

-- For a timeout-based approach (1 second timeout as you specified)
-- PostgreSQL doesn't have a built-in pg_try_advisory_lock_with_timeout,
-- but you can implement it using statement_timeout:

DO $$
DECLARE
    lock_acquired boolean;
BEGIN
    -- Set statement timeout to 1 second
    SET LOCAL statement_timeout = '1s';

    -- Try to acquire the lock (this will timeout after 1 second)
    PERFORM pg_advisory_lock(lkhndl);
    lock_acquired := true;

EXCEPTION
    WHEN query_canceled THEN
        lock_acquired := false;
END $$;

-- Or as a reusable function:
CREATE OR REPLACE FUNCTION pg_try_advisory_lock_with_timeout(key bigint, timeout_seconds int DEFAULT 1)
RETURNS boolean AS $$
DECLARE
    lock_acquired boolean := false;
BEGIN
    -- Set statement timeout
    EXECUTE format('SET LOCAL statement_timeout = ''%ss''', timeout_seconds);

    -- Try to acquire the lock
    PERFORM pg_advisory_lock(key);
    lock_acquired := true;

    RETURN lock_acquired;

EXCEPTION
    WHEN query_canceled THEN
        RETURN false;
END;
$$ LANGUAGE plpgsql;

-- Usage:
SELECT pg_try_advisory_lock_with_timeout(lkhndl, 1)

