CREATE OR REPLACE FUNCTION reindex_superhero_ids(IN BIGINT) 
RETURNS VOID 
LANGUAGE plpgsql 
AS $$ 
BEGIN
    CREATE TEMPORARY SEQUENCE IF NOT EXISTS id_seq_temp MINVALUE 1 START WITH 1 INCREMENT BY 1;
    ALTER SEQUENCE id_seq_temp RESTART WITH 1;

    UPDATE superhero 
    SET hair_colour_id = hair_colour_id + 2000 
    WHERE publisher_id = $1;

    UPDATE superhero 
    SET hair_colour_id = nextval('id_seq_temp') 
    WHERE publisher_id = $1
    ORDER BY id;

    DROP SEQUENCE IF EXISTS id_seq_temp;
END;
$$

CREATE TABLE log_content (
    "log_id" INT GENERATED BY DEFAULT AS IDENTITY NOT NULL, 
    "content" VARCHAR(32) NOT NULL, 
    "no_of_chars" INT NULL, 
    PRIMARY KEY ("log_id")
);

CREATE OR REPLACE FUNCTION update_no_of_chars()
RETURNS TRIGGER AS $$
BEGIN
    NEW.no_of_chars := CHAR_LENGTH(NEW.content);
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trigger_update_no_of_chars
BEFORE INSERT OR UPDATE ON log_content
FOR EACH ROW
EXECUTE FUNCTION update_no_of_chars()

CREATE TABLE content (
    id serial PRIMARY KEY NOT NULL, 
    item_id int NOT NULL, 
    nested_item_id int REFERENCES content(id), 
    block_id int, 
    "order" int NOT NULL
);

CREATE OR REPLACE FUNCTION prevent_self_reference()
RETURNS TRIGGER AS $$
BEGIN
    IF NEW.nested_item_id = NEW.id THEN
        RAISE EXCEPTION 'A row cannot reference itself: nested_item_id cannot equal id';
    END IF;
    RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER check_self_reference
    BEFORE INSERT OR UPDATE ON content
    FOR EACH ROW
    EXECUTE FUNCTION prevent_self_reference()

